settings.custom_css:
/* input field css */
selector input::placeholder{
    opacity: 1;
}

selector input:focus::placeholder {
    opacity: 0;
    transition: all 0.4s;
}

/* textarea field css */
selector textarea::placeholder{
    opacity: 1;
}

selector textarea:focus::placeholder {
    opacity: 0;
    transition: all 0.4s;
}

selector .elementor-select-wrapper::before {
    color: #001689!important;
}

selector textarea {
    resize: none;
}

selector input {
    direction: rtl;
}

.elementor-field-group-email label, .elementor-field-group-name label, .elementor-field-group-phone label {
    display: none !important;
}


.e-form__buttons {
    padding-top: 1.4em;
}

.elementor-field-type-html.elementor-field-group.elementor-column.elementor-field-group-field_65ac176.elementor-col-100 {
    margin-top: 0.5em;
    margin-bottom: 0.4em;
}


