/* Part's */
.elementor-field-type-step.elementor-column.elementor-field-group-part1.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part2.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part3.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part4.elementor-col-100.e-form__step{
    background-color: #FFF !important;
    border-radius: 30px;
    padding: 2%;
}

@media only screen and (max-width: 1024px) {
    .elementor-field-type-step.elementor-column.elementor-field-group-part1.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part2.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part3.elementor-col-100.e-form__step,
.elementor-field-type-step.elementor-column.elementor-field-group-part4.elementor-col-100.e-form__step{

    padding: 2em 1.1em;
}



