selector [type="radio"]:checked,
selector [type="radio"]:not(:checked) {
    position: absolute;
    visibility: hidden;
}

selector .elementor-field-option label {
    display: block;
    padding: 0px 30px;
    margin: 6px 0;
    transition: 0.2s all;
    cursor: pointer;
    position: relative;
    z-index: 2;
}

selector .elementor-field-option label:after {
    width: 18px;
    height: 18px;
    content: "";
    border: 1px solid #EBE9E8;
    background-color: #EBE9E8;
    background-repeat: no-repeat;
    border-radius: 35px;
    background-position: 1px 2px;
    z-index: 2;
    position: absolute;
    right: 0px;
    top: 50%;
    transform: translateY(-50%);
    cursor: pointer;
    transition: all 200ms ease-in;

}

selector .elementor-field-type-radio label {
    margin-top: 1.2%;
}

selector input[type="radio"]:checked ~ label:after {
    background-color: #F05C6E;
    border-color: #fff;
    border-radius: 35px;
    border: 3px solid #EBE9E8;
}
